import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, Select, MenuItem, Box } from '@material-ui/core';

export default function BillManagement() {
  const [bills, setBills] = useState([]);
  const [sales, setSales] = useState([]);
  const [companies, setCompanies] = useState([]);
  const [newBill, setNewBill] = useState({ sales: [], company: { id: '' }, paymentPending: true });

  useEffect(() => {
    axios.get('http://localhost:8080/api/bills').then(res => setBills(res.data));
    axios.get('http://localhost:8080/api/sales').then(res => setSales(res.data));
    axios.get('http://localhost:8080/api/companies').then(res => setCompanies(res.data));
  }, []);

  const addBill = () => {
    axios.post('http://localhost:8080/api/bills', newBill).then(res => {
      setBills([...bills, res.data]);
      setNewBill({ sales: [], company: { id: '' }, paymentPending: true });
    });
  };

  const downloadPdf = (id) => {
    axios.get(`http://localhost:8080/api/bills/${id}/pdf`, { responseType: 'blob' }).then(res => {
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `bill-${id}.pdf`);
      document.body.appendChild(link);
      link.click();
    });
  };

  return (
    <div>
      <Box marginBottom={2}>
        <Select
          multiple
          value={newBill.sales}
          onChange={e => setNewBill({ ...newBill, sales: e.target.value })}
        >
          {sales.map(sale => (
            <MenuItem key={sale.id} value={sale}>{sale.item.name} - {sale.quantity}</MenuItem>
          ))}
        </Select>
        <Select
          value={newBill.company.id}
          onChange={e => setNewBill({ ...newBill, company: { id: e.target.value } })}
        >
          {companies.map(company => (
            <MenuItem key={company.id} value={company.id}>{company.name}</MenuItem>
          ))}
        </Select>
        <Button onClick={addBill} color="primary" variant="contained">Create Bill</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Bill ID</TableCell>
            <TableCell>Company</TableCell>
            <TableCell>Total Amount</TableCell>
            <TableCell>Payment Pending</TableCell>
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {bills.map(bill => (
            <TableRow key={bill.id}>
              <TableCell>{bill.id}</TableCell>
              <TableCell>{bill.company.name}</TableCell>
              <TableCell>{bill.totalAmount}</TableCell>
              <TableCell>{bill.paymentPending ? 'Yes' : 'No'}</TableCell>
              <TableCell>
                <Button onClick={() => downloadPdf(bill.id)} color="primary">Download PDF</Button>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
